changeSet.sql:
DO $$
DECLARE c_name text;
BEGIN
    SELECT conname INTO c_name FROM pg_constraint
     WHERE conrelid = 'orders'::regclass
       AND contype = 'f'
       AND pg_get_constraintdef(oid) LIKE '%REFERENCES users%';
    IF c_name IS NOT NULL THEN
        EXECUTE format('ALTER TABLE orders DROP CONSTRAINT %I', c_name);
    END IF;
END $$;

ALTER TABLE orders
    ADD CONSTRAINT fk_orders_user
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE SET NULL;

rollback.sql:
ALTER TABLE orders DROP CONSTRAINT IF EXISTS fk_orders_user;
ALTER TABLE orders
    ADD CONSTRAINT orders_user_id_fkey
    FOREIGN KEY (user_id) REFERENCES users(id);
ALTER TABLE orders ALTER COLUMN user_id SET NOT NULL;

